### Pattern 4: Processing Fields with Relations

**From:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775389478214-8x8i0j/packages/client-generator-ts/src/TSClient/Payload.ts`

```typescript
function buildModelPayload(model: DMMF.Model, context: GenerateContext) {
  const scalars = []
  const objects = []
  const composites = []

  for (const field of model.fields) {
    if (field.kind === 'object') {
      // This is a relation
      if (context.dmmf.isComposite(field.type)) {
        // Relation to composite type
        composites.push(field)
      } else {
        // Relation to model
        objects.push(field)
      }
    } else if (field.kind === 'enum' || field.kind === 'scalar') {
      scalars.push(field)
    }
  }

  // Process relation metadata
  for (const field of model.fields) {
    if (field.kind === 'object') {
      console.log(`Relation: ${field.name}`)
      console.log(`  To model: ${field.type}`)
      console.log(`  Relation name: ${field.relationName}`)
      console.log(`  From fields: ${field.relationFromFields}`)  // Local FK columns
      console.log(`  To fields: ${field.relationToFields}`)      // Remote ID columns
      console.log(`  On delete: ${field.relationOnDelete}`)      // CASCADE, SET_NULL, etc.
    }
  }
}
```

