  const dbName = model.dbName
  const documentation = model.documentation

  // Iterate over fields
  for (const field of model.fields) {
    console.log(`Field: ${field.name}`)
    console.log(`  Kind: ${field.kind}`)           // 'scalar', 'object', 'enum', 'unsupported'
    console.log(`  Type: ${field.type}`)           // String, Int, User (for relations), etc.
    console.log(`  Required: ${field.isRequired}`) // Not nullable
    console.log(`  List: ${field.isList}`)         // Array type []
