import type * as DMMF from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { generate } from '../generator'

function createField(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  }
}

function createModel(name: string, fields: DMMF.Field[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  }
}

function createDmmf(models: DMMF.Model[], enums: DMMF.DatamodelEnum[] = []): DMMF.Document {
  return {
    datamodel: {
      models,
      enums,
      types: [],
      indexes: [],
    },
    schema: {
      inputObjectTypes: {},
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: {
      modelOperations: [],
      otherOperations: { read: [], write: [] },
    },
  }
}

describe('generate', () => {
  test('generates file header', () => {
    const dmmf = createDmmf([])
    const result = generate(dmmf)

    expect(result).toContain('// This file was generated by @prisma/generator-rest-client.')
    expect(result).toContain('// Do not edit it manually.')
  })

  test('generates model interface with scalar fields', () => {
    const model = createModel('User', [
      createField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      createField({ name: 'email', type: 'String', isUnique: true }),
      createField({ name: 'name', type: 'String', isRequired: false }),
    ])
    const result = generate(createDmmf([model]))

    expect(result).toContain('export interface User {')
    expect(result).toContain('id: number')
    expect(result).toContain('email: string')
    expect(result).toContain('name?: string | null')
  })

  test('generates CreateInput with optional id and default fields', () => {
    const model = createModel('User', [
      createField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      createField({ name: 'email', type: 'String' }),
      createField({ name: 'name', type: 'String', isRequired: false }),
    ])
    const result = generate(createDmmf([model]))

    expect(result).toContain('export interface UserCreateInput {')
    expect(result).toMatch(/id\?: number/)
    expect(result).toContain('email: string')
  })

  test('generates UpdateInput with all optional fields', () => {
    const model = createModel('User', [
      createField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      createField({ name: 'email', type: 'String' }),
    ])
    const result = generate(createDmmf([model]))

    expect(result).toContain('export interface UserUpdateInput {')
    expect(result).toContain('email?: string')
  })

  test('generates WhereUniqueInput from id and unique fields', () => {
    const model = createModel('User', [
      createField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      createField({ name: 'email', type: 'String', isUnique: true }),
      createField({ name: 'name', type: 'String' }),
    ])
    const result = generate(createDmmf([model]))

    expect(result).toContain('export interface UserWhereUniqueInput {')
    expect(result).toContain('id?: number')
    expect(result).toContain('email?: string')
    expect(result).not.toMatch(/UserWhereUniqueInput[\s\S]*?name\?/)
  })

  test('generates model client class with CRUD methods', () => {
    const model = createModel('Post', [
      createField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      createField({ name: 'title', type: 'String' }),
    ])
    const result = generate(createDmmf([model]))

    expect(result).toContain('export class PostClient {')
    expect(result).toContain('async findMany(')
    expect(result).toContain('async findUnique(where: PostWhereUniqueInput)')
    expect(result).toContain('async create(data: PostCreateInput)')
    expect(result).toContain('async update(where: PostWhereUniqueInput, data: PostUpdateInput)')
    expect(result).toContain('async delete(where: PostWhereUniqueInput)')
  })

  test('generates main RestClient class with model properties', () => {
    const user = createModel('User', [
      createField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
    ])
    const post = createModel('Post', [
      createField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
    ])
    const result = generate(createDmmf([user, post]))

    expect(result).toContain('export class RestClient {')
    expect(result).toContain('readonly user: UserClient')
    expect(result).toContain('readonly post: PostClient')
    expect(result).toContain('this.user = new UserClient(')
    expect(result).toContain('this.post = new PostClient(')
  })

  test('generates enums', () => {
    const dmmf = createDmmf([], [
      {
        name: 'Role',
        values: [
          { name: 'ADMIN', dbName: null },
          { name: 'USER', dbName: null },
        ],
      },
    ])
    const result = generate(dmmf)

    expect(result).toContain('export enum Role {')
    expect(result).toContain("ADMIN = 'ADMIN',")
    expect(result).toContain("USER = 'USER',")
  })

  test('maps all scalar types correctly', () => {
    const model = createModel('TypeTest', [
      createField({ name: 'id', type: 'Int', isId: true }),
      createField({ name: 'str', type: 'String' }),
      createField({ name: 'bool', type: 'Boolean' }),
      createField({ name: 'float', type: 'Float' }),
      createField({ name: 'decimal', type: 'Decimal' }),
      createField({ name: 'bigint', type: 'BigInt' }),
      createField({ name: 'date', type: 'DateTime' }),
      createField({ name: 'json', type: 'Json' }),
      createField({ name: 'bytes', type: 'Bytes' }),
    ])
    const result = generate(createDmmf([model]))

    expect(result).toContain('str: string')
    expect(result).toContain('bool: boolean')
    expect(result).toContain('float: number')
    expect(result).toContain('decimal: string')
    expect(result).toContain('bigint: bigint')
    expect(result).toContain('date: string')
    expect(result).toContain('json: unknown')
    expect(result).toContain('bytes: string')
  })

  test('handles list fields', () => {
    const model = createModel('Post', [
      createField({ name: 'id', type: 'Int', isId: true }),
      createField({ name: 'tags', type: 'String', isList: true }),
    ])
    const result = generate(createDmmf([model]))

    expect(result).toContain('tags: string[]')
  })

  test('excludes relation fields from interfaces', () => {
    const model = createModel('Post', [
      createField({ name: 'id', type: 'Int', isId: true }),
      createField({ name: 'title', type: 'String' }),
      createField({
        name: 'author',
        type: 'User',
        kind: 'object',
        relationName: 'PostToUser',
        relationFromFields: ['authorId'],
        relationToFields: ['id'],
      }),
      createField({ name: 'authorId', type: 'Int' }),
    ])
    const result = generate(createDmmf([model]))

    expect(result).toContain('title: string')
    expect(result).toContain('authorId: number')
    expect(result).not.toMatch(/author\??: User/)
  })

  test('uses correct REST endpoints with camelCase model names', () => {
    const model = createModel('BlogPost', [
      createField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
    ])
    const result = generate(createDmmf([model]))

    expect(result).toContain('/blogPost')
    expect(result).toContain('readonly blogPost: BlogPostClient')
  })

  test('findUnique uses id field for URL', () => {
    const model = createModel('User', [
      createField({ name: 'id', type: 'Int', isId: true }),
      createField({ name: 'email', type: 'String', isUnique: true }),
    ])
    const result = generate(createDmmf([model]))

    expect(result).toContain('where.id')
  })

  test('findUnique falls back to unique field when no id', () => {
    const model = createModel('Setting', [
      createField({ name: 'key', type: 'String', isUnique: true }),
      createField({ name: 'value', type: 'String' }),
    ])
    const result = generate(createDmmf([model]))

    expect(result).toContain('where.key')
  })

  test('generates constructor with baseUrl and optional fetcher', () => {
    const model = createModel('User', [
      createField({ name: 'id', type: 'Int', isId: true }),
    ])
    const result = generate(createDmmf([model]))

    expect(result).toContain("constructor(options: { baseUrl: string; fetcher?: typeof fetch })")
    expect(result).toContain("options.fetcher ?? globalThis.fetch.bind(globalThis)")
  })
})

