{
  "name": "@prisma/generator-rest-client",
  "version": "0.0.0",
  "description": "Prisma generator that creates a typed REST API client from a Prisma schema",
  "main": "dist/index.js",
  "module": "dist/index.mjs",
  "types": "dist/index.d.ts",
  "exports": {
    ".": {
      "require": {
        "types": "./dist/index.d.ts",
        "default": "./dist/index.js"
      },
      "import": {
        "types": "./dist/index.d.ts",
        "default": "./dist/index.mjs"
      }
    }
  },
  "repository": {
    "type": "git",
    "url": "https://github.com/prisma/prisma.git",
    "directory": "packages/generator-rest-client"
  },
  "license": "Apache-2.0",
  "dependencies": {
    "@prisma/generator-helper": "workspace:*"
  },
  "devDependencies": {
    "@prisma/dmmf": "workspace:*",
    "@prisma/generator": "workspace:*"
  },
  "scripts": {
    "dev": "DEV=true tsx helpers/build.ts",
    "build": "tsx helpers/build.ts",
    "prepublishOnly": "pnpm run build",
    "test": "vitest run"
  },
  "files": [
    "dist"
  ],
  "sideEffects": false
}

import fs from 'node:fs'
import path from 'node:path'

import { generatorHandler } from '@prisma/generator-helper'

import { generate } from './generator'

generatorHandler({
  onManifest() {
    return {
      prettyName: 'Prisma REST Client Generator',
      defaultOutput: './generated/rest-client',
    }
  },

  async onGenerate(options) {
    const output = options.generator.output?.value
    if (!output) {
      throw new Error('@prisma/generator-rest-client: No output directory specified.')
    }

    const content = generate(options.dmmf)

    await fs.promises.mkdir(output, { recursive: true })
    await fs.promises.writeFile(path.join(output, 'rest-client.ts'), content, 'utf-8')
  },
})

import type * as DMMF from '@prisma/dmmf'

import { block, exportInterface, fileHeader, joinSections } from './template'

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'string',
  BigInt: 'bigint',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
}

/** Map a DMMF field type to a TypeScript type string. */
function mapFieldType(field: DMMF.Field): string {
  let tsType: string

  switch (field.kind) {
    case 'scalar':
      tsType = SCALAR_TYPE_MAP[field.type] ?? 'unknown'
      break
    case 'enum':
      tsType = field.type
      break
    case 'object':
      tsType = field.type
      break
    default:
      tsType = 'unknown'
  }

  if (field.isList) {
    tsType = `${tsType}[]`
  }

  if (!field.isRequired && !field.isList) {
    tsType = `${tsType} | null`
  }

  return tsType
}

/** Generate a TypeScript interface for a single DMMF model. */
function generateModelInterface(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .map((field) => {
      const optional = !field.isRequired && !field.isList ? '?' : ''
      return `${field.name}${optional}: ${mapFieldType(field)}`
    })

  return exportInterface(model.name, fields.join('\n'))
}

/** Generate a CreateInput type for a model (excludes auto-generated fields). */
function generateCreateInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .filter((f) => !f.isGenerated && !f.isUpdatedAt)
    .map((field) => {
      const optional = !field.isRequired || field.hasDefaultValue || field.isId ? '?' : ''
      return `${field.name}${optional}: ${mapFieldType(field)}`
    })

  return exportInterface(`${model.name}CreateInput`, fields.join('\n'))
}

/** Generate an UpdateInput type for a model (all fields optional). */
function generateUpdateInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .filter((f) => !f.isGenerated && !f.isReadOnly)
    .map((field) => {
      const baseType = mapFieldType(field)
      return `${field.name}?: ${baseType}`
    })

  return exportInterface(`${model.name}UpdateInput`, fields.join('\n'))
}

/** Generate a WhereUniqueInput type for a model (id and unique fields). */
function generateWhereUniqueInput(model: DMMF.Model): string {
  const uniqueFields = model.fields.filter((f) => f.kind !== 'object' && (f.isId || f.isUnique))

  const fields = uniqueFields.map((field) => `${field.name}?: ${mapFieldType(field)}`)

  return exportInterface(`${model.name}WhereUniqueInput`, fields.join('\n'))
}

/** Generate CRUD methods for a single model. */
function generateModelClient(model: DMMF.Model): string {
  const name = model.name
  const camelName = name.charAt(0).toLowerCase() + name.slice(1)

  const methods = [
    `  async findMany(params?: { skip?: number; take?: number }): Promise<${name}[]> {`,
    `    const query = new URLSearchParams()`,
    `    if (params?.skip !== undefined) query.set('skip', String(params.skip))`,
    `    if (params?.take !== undefined) query.set('take', String(params.take))`,
    `    const qs = query.toString()`,
    `    const url = \`\${this.baseUrl}/${camelName}\${qs ? '?' + qs : ''}\``,
    `    const response = await this.fetcher(url, { method: 'GET' })`,
    `    return response.json() as Promise<${name}[]>`,
    `  }`,
    ``,
    `  async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {`,
    `    const id = ${getIdAccessExpression(model)}`,
    `    const url = \`\${this.baseUrl}/${camelName}/\${encodeURIComponent(String(id))}\``,
    `    const response = await this.fetcher(url, { method: 'GET' })`,
    `    if (response.status === 404) return null`,
    `    return response.json() as Promise<${name}>`,
    `  }`,
    ``,
    `  async create(data: ${name}CreateInput): Promise<${name}> {`,
    `    const url = \`\${this.baseUrl}/${camelName}\``,
    `    const response = await this.fetcher(url, {`,
    `      method: 'POST',`,
    `      headers: { 'Content-Type': 'application/json' },`,
    `      body: JSON.stringify(data),`,
    `    })`,
    `    return response.json() as Promise<${name}>`,
    `  }`,
    ``,
    `  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {`,
    `    const id = ${getIdAccessExpression(model)}`,
    `    const url = \`\${this.baseUrl}/${camelName}/\${encodeURIComponent(String(id))}\``,
    `    const response = await this.fetcher(url, {`,
    `      method: 'PATCH',`,
    `      headers: { 'Content-Type': 'application/json' },`,
    `      body: JSON.stringify(data),`,
    `    })`,
    `    return response.json() as Promise<${name}>`,
    `  }`,
    ``,
    `  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {`,
    `    const id = ${getIdAccessExpression(model)}`,
    `    const url = \`\${this.baseUrl}/${camelName}/\${encodeURIComponent(String(id))}\``,
    `    const response = await this.fetcher(url, { method: 'DELETE' })`,
    `    return response.json() as Promise<${name}>`,
    `  }`,
  ]

  return block(`export class ${name}Client`, [
    `readonly #baseUrl: string`,
    `readonly #fetcher: typeof fetch`,
    ``,
    `constructor(baseUrl: string, fetcher: typeof fetch) {`,
    `  this.#baseUrl = baseUrl`,
    `  this.#fetcher = fetcher`,
    `}`,
    ``,
    `private get baseUrl(): string { return this.#baseUrl }`,
    `private get fetcher(): typeof fetch { return this.#fetcher }`,
    ``,
    ...methods,
  ].join('\n'))
}

/** Get the expression to access the ID field from a where-unique input. */
function getIdAccessExpression(model: DMMF.Model): string {
  const idField = model.fields.find((f) => f.isId)
  if (idField) {
    return `where.${idField.name}`
  }

  const uniqueField = model.fields.find((f) => f.isUnique && f.kind !== 'object')
  if (uniqueField) {
    return `where.${uniqueField.name}`
  }

  return `Object.values(where)[0]`
}

/** Generate a TypeScript enum declaration from a DMMF enum. */
function generateEnum(enumDef: DMMF.DatamodelEnum): string {
  const members = enumDef.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
  return `export enum ${enumDef.name} {\n${members}\n}`
}

/** Generate the main REST client class that aggregates all model clients. */
function generateMainClient(models: readonly DMMF.Model[]): string {
  const properties = models.map((model) => {
    const camelName = model.name.charAt(0).toLowerCase() + model.name.slice(1)
    return `  readonly ${camelName}: ${model.name}Client`
  })

  const assignments = models.map((model) => {
    const camelName = model.name.charAt(0).toLowerCase() + model.name.slice(1)
    return `    this.${camelName} = new ${model.name}Client(this.#baseUrl, this.#fetcher)`
  })

  return [
    `export class RestClient {`,
    `  readonly #baseUrl: string`,
    `  readonly #fetcher: typeof fetch`,
    ``,
    ...properties,
    ``,
    `  constructor(options: { baseUrl: string; fetcher?: typeof fetch }) {`,
    `    this.#baseUrl = options.baseUrl.replace(/\\/$/, '')`,
    `    this.#fetcher = options.fetcher ?? globalThis.fetch.bind(globalThis)`,
    ...assignments,
    `  }`,
    `}`,
  ].join('\n')
}

/**
 * Generate the complete REST client TypeScript source from a DMMF document.
 * Returns the content of the `rest-client.ts` file.
 */
export function generate(dmmf: DMMF.Document): string {
  const models = dmmf.datamodel.models
  const enums = dmmf.datamodel.enums

  const sections: string[] = [fileHeader()]

  for (const enumDef of enums) {
    sections.push(generateEnum(enumDef))
  }

  for (const model of models) {
    sections.push(generateModelInterface(model))
    sections.push(generateCreateInput(model))
    sections.push(generateUpdateInput(model))
    sections.push(generateWhereUniqueInput(model))
  }

  for (const model of models) {
    sections.push(generateModelClient(model))
  }

  sections.push(generateMainClient(models))

  return joinSections(sections) + '\n'
}

/**
 * String template helpers for generating TypeScript code.
 */

/** Indent every line of `text` by `level` × 2 spaces. */
export function indent(text: string, level: number): string {
  const prefix = '  '.repeat(level)
  return text
    .split('\n')
    .map((line) => (line.trim() === '' ? '' : prefix + line))
    .join('\n')
}

/** Wrap a block of lines in curly braces with the given header. */
export function block(header: string, body: string): string {
  return `${header} {\n${indent(body, 1)}\n}`
}

/** Generate a TypeScript `export interface` declaration. */
export function exportInterface(name: string, body: string): string {
  return block(`export interface ${name}`, body)
}

/** Join multiple code sections with blank-line separators. */
export function joinSections(sections: string[]): string {
  return sections.join('\n\n')
}

/** Generate a file header comment. */
export function fileHeader(): string {
  return [
    '// This file was generated by @prisma/generator-rest-client.',
    '// Do not edit it manually.',
    '',
  ].join('\n')
}
